general_error__text = TextObject(bs_BA="Došlo je do greške. Pokušajte ponovo kasnije.", cs_CZ="Vyskytla se chyba. Zkuste to prosím znovu později.", da_DK="Fejl opstået. Forsøg igen senere.", de_DE="Es ist ein Fehler aufgetreten. Bitte versuche es später erneut.", el_GR="Προέκυψε σφάλμα. Προσπαθήστε πάλι αργότερα.", en_GB="An error has occurred. Please try again later.", es_ES="Se ha producido un error. Por favor, inténtelo de nuevo más tarde.", fi_FI="Tapahtui virhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur s'est produite. Veuillez réessayer ultérieurement.", hr_HR="Nastupila je greška. Pokušajte ponovno kasnije.", hu_HU="Hiba lépett fel. Kérünk, próbáld újra.", it_IT="Si è verificato un errore. Si prega di riprovare più tardi.", nl_NL="Er is een fout opgetreden. Probeer het later opnieuw.", no_NO="Det har oppstått en feil. Prøv igjen senere.", pl_PL="Wystąpił błąd. Proszę spróbować ponownie później.", pt_PT="Ocorreu uma falha. Por favor, volta a tentar.", ro_RO="A apărut o eroare. Reîncercaţi mai târziu.", ru_RU="Произошла ошибка. Повторите попытку.", sk_SK="Vyskytla sa chyba. Prosím, pokúste sa o to znovu neskôr.", sl_SI="Prišlo je do napake. Poskusite znova.", sr_RS="Došlo je do greške. Pokušajte ponovo kasnije.", sv_SE="Ett fel har uppstått. Försök igen senare.", tr_TR="Bir hata oluştu. Lütfen daha sonra yeniden dene.", uk_UA="Сталася помилка. Повторіть спробу пізніше.")
