start_page__hfl_disabled_text = TextObject(bs_BA="Aktivacijska riječ „Alexa“ je isključena", cs_CZ="Aktivační slovo \"Alexa\" je vypnuté", da_DK="Aktiveringsordet \"Alexa\" er deaktiveret.", de_DE="Aktivierungswort \"Alexa\" ist ausgeschaltet", el_GR="Η φράση ενεργοποίησης \"Alexa\" είναι απενεργοποιημένη", en_GB="\"Alexa\" wake word is switched off", es_ES="La palabra de activación \"Alexa\" está desactivada", fi_FI="Aktivointisana \"Alexa\" on kytketty pois päältä", fr_FR="Le mot d'activation «Alexa» est désactivé", hr_HR="Riječ za aktiviranje \"Alexa\" je isključena", hu_HU="„Alexa” aktiválószó kikapcsolva", it_IT="La parola di attivazione \"Alexa\" è disattivata", nl_NL="Activeringswoord \"Alexa\"is uitgeschakeld", no_NO="Aktiveringsordet «Alexa» er slått av", pl_PL="Słowo aktywujące „Alexa” jest wyłączone", pt_PT="Palavra de ativação \"Alexa\" está desligada", ro_RO="Cuvântul de activare \"Alexa\" este dezactivat", ru_RU="Слово активации «Alexa» выключено", sk_SK="Aktivačné slovo “Alexa“ je vypnuté", sl_SI="Aktivacijska beseda \"Alexa\" je izključena", sr_RS="Aktivacijska reč „Alexa“ je isključena", sv_SE="Aktiveringsordet ”Alexa” är avaktiverat", tr_TR="\"Alexa\" aktivasyon kelimesi kapalı", uk_UA="Активаційне слово «Alexa» вимкнено")
